import express from "express";
import path from "path";
import fs from "fs";
import dotenv from "dotenv";
import { GoogleGenAI } from "@google/genai";
import { createServer as createViteServer } from "vite";
import { initializeApp } from "firebase/app";
import { initializeFirestore, collection, addDoc, getDocs, setLogLevel, getCountFromServer, serverTimestamp, doc, getDoc, setDoc, increment } from "firebase/firestore";

dotenv.config();

const app = express();
const PORT = 3000;

app.use(express.json());

// Serve uploaded assets folder statically
app.use("/assets", express.static(path.join(process.cwd(), "assets")));

// Simple file-based or in-memory database path
const DB_PATH = path.join(process.cwd(), "db_store.json");

interface Feedback {
  name: string;
  email: string;
  background: string; // Casual, KSP Veteran, Engineer, Developer
  favoriteCriteria: string; // Physics, Tech Tree, Stability, Multiplayer, Modding, Value, etc.
  desiredPrice: string; // Free, $15-$25, $30-$40, $50+
  rating: number; // 1-5 how excited they are
  comments: string;
  timestamp: string;
}

interface Subscriber {
  email: string;
  timestamp: string;
}

// Initial seed data so the dashboard is interactive from the first load
const SEED_SUBSCRIBERS: Subscriber[] = [];

const SEED_FEEDBACK: Feedback[] = [];

let db: { subscribers: Subscriber[]; feedback: Feedback[] } = {
  subscribers: [...SEED_SUBSCRIBERS],
  feedback: [...SEED_FEEDBACK]
};

let globalSyncWithFirestore: (() => Promise<void>) | null = null;

// Load database if exists
function loadDb() {
  try {
    if (fs.existsSync(DB_PATH)) {
      const data = fs.readFileSync(DB_PATH, "utf-8");
      const parsed = JSON.parse(data);
      if (parsed.subscribers && parsed.feedback) {
        db = parsed;
      }
    } else {
      saveDb();
    }
  } catch (err) {
    console.error("Error loading database, defaulting to seeds:", err);
  }
}

// Save database
function saveDb() {
  try {
    fs.writeFileSync(DB_PATH, JSON.stringify(db, null, 2), "utf-8");
  } catch (err) {
    console.error("Error saving database:", err);
  }
}

loadDb();

enum OperationType {
  CREATE = 'create',
  UPDATE = 'update',
  DELETE = 'delete',
  LIST = 'list',
  GET = 'get',
  WRITE = 'write',
}

interface FirestoreErrorInfo {
  error: string;
  operationType: OperationType;
  path: string | null;
  authInfo: {
    userId?: string | null;
    email?: string | null;
    emailVerified?: boolean | null;
    isAnonymous?: boolean | null;
    tenantId?: string | null;
    providerInfo?: {
      providerId?: string | null;
      email?: string | null;
    }[];
  }
}

function handleFirestoreError(error: unknown, operationType: OperationType, path: string | null): never {
  const errInfo: FirestoreErrorInfo = {
    error: error instanceof Error ? error.message : String(error),
    authInfo: {
      userId: null,
      email: null,
      emailVerified: null,
      isAnonymous: null,
      tenantId: null,
      providerInfo: []
    },
    operationType,
    path
  };
  console.info('[FIREBASE] Diagnostic JSON info: ', JSON.stringify(errInfo));
  throw new Error(JSON.stringify(errInfo));
}

// Firebase Initialization
const CONFIG_PATH = path.join(process.cwd(), "firebase-applet-config.json");
let firestoreDb: any = null;

if (fs.existsSync(CONFIG_PATH)) {
  try {
    const firebaseConfig = JSON.parse(fs.readFileSync(CONFIG_PATH, "utf-8"));
    const firebaseApp = initializeApp(firebaseConfig);
    
    // Silence noisy internal Firestore background warnings like idle stream disconnections
    setLogLevel("error");
    
    const dbId = firebaseConfig.firestoreDatabaseId;
    if (dbId && dbId !== "(default)") {
      firestoreDb = initializeFirestore(firebaseApp, {
        experimentalForceLongPolling: true,
      }, dbId);
      console.log("[FIREBASE] Connected to Firestore via long polling with database ID: " + dbId);
    } else {
      firestoreDb = initializeFirestore(firebaseApp, {
        experimentalForceLongPolling: true,
      });
      console.log("[FIREBASE] Connected to default Firestore database via long polling");
    }

    // Initial sync of subscribers on boot
    const syncWithFirestore = async () => {
      try {
        console.log("[FIREBASE] Intending direct read/write synchronization with Cloud Firestore.");
        const subscribersCol = collection(firestoreDb, "subscribers");
        const snapshot = await getDocs(subscribersCol);

        console.log(`[FIREBASE] Synced ${snapshot.size} subscribers from Firestore.`);
        snapshot.forEach((doc) => {
          const data = doc.data();
          if (data && data.email) {
            if (!db.subscribers.some((s) => s.email.toLowerCase() === data.email.toLowerCase())) {
              db.subscribers.push({
                email: data.email,
                timestamp: data.timestamp || new Date().toISOString()
              });
            }
          }
        });

        // Bidirectional Sync: Upload any offline or cached local subscribers missing in Firestore
        for (const localSub of db.subscribers) {
          const existsInCloud = snapshot.docs.some(
            (doc) => doc.data()?.email?.toLowerCase() === localSub.email.toLowerCase()
          );
          if (!existsInCloud) {
            try {
              await addDoc(subscribersCol, {
                email: localSub.email,
                timestamp: localSub.timestamp
              });
              console.log(`[FIREBASE] Synchronized subscriber upwards to Cloud Firestore: ${localSub.email}`);
            } catch (upErr) {
              console.warn(`[FIREBASE] Failed uploading subscriber database sync:`, upErr);
            }
          }
        }

        const feedbackCol = collection(firestoreDb, "feedback");
        const feedbackSnapshot = await getDocs(feedbackCol);

        console.log(`[FIREBASE] Synced ${feedbackSnapshot.size} feedback entries from Firestore.`);
        feedbackSnapshot.forEach((doc) => {
          const data = doc.data() as any;
          if (data && data.email && data.name) {
            if (!db.feedback.some((f) => f.email.toLowerCase() === data.email.toLowerCase() && f.timestamp === data.timestamp)) {
              db.feedback.push({
                name: data.name,
                email: data.email,
                background: data.background || "Space Sim Veteran",
                favoriteCriteria: data.favoriteCriteria || "01 PHYSICS FIDELITY",
                desiredPrice: data.desiredPrice || "$30-$40",
                rating: typeof data.rating === "number" ? data.rating : 5,
                comments: data.comments || "",
                timestamp: data.timestamp || new Date().toISOString()
              });
            }
          }
        });

        // Bidirectional Sync: Upload any offline or cached local feedback missing in Firestore
        for (const localFeed of db.feedback) {
          const existsInCloud = feedbackSnapshot.docs.some((doc) => {
            const data = doc.data() as any;
            return data?.email?.toLowerCase() === localFeed.email.toLowerCase() && data?.timestamp === localFeed.timestamp;
          });
          if (!existsInCloud) {
            try {
              await addDoc(feedbackCol, {
                name: localFeed.name,
                email: localFeed.email,
                background: localFeed.background,
                favoriteCriteria: localFeed.favoriteCriteria,
                desiredPrice: localFeed.desiredPrice,
                rating: localFeed.rating,
                comments: localFeed.comments,
                timestamp: localFeed.timestamp
              });
              console.log(`[FIREBASE] Synchronized feedback report upwards to Cloud Firestore: ${localFeed.email}`);
            } catch (upErr) {
              console.warn(`[FIREBASE] Failed uploading feedback database sync:`, upErr);
            }
          }
        }

        saveDb();
        console.log("[FIREBASE] Database synchronization complete.");
      } catch (syncErr: any) {
        console.error("[FIREBASE] Boot synchronization failure:", syncErr?.message || syncErr);
      }
    };

    globalSyncWithFirestore = syncWithFirestore;
    syncWithFirestore();
  } catch (err) {
    console.error("[FIREBASE] Initialization failed:", err);
  }
} else {
  console.log("[FIREBASE] Config not found, operating in offline/local mock database mode.");
}

